"""
MKT Original Commentary — Mark chapters 1–2
Run: python3 scripts/zc-original-mark-1-2.py

Source data used:
- data/interlinear/mark.json
- data/translation/draft/mediating/mark.json
- data/translation/notes/mark.json
- data/commentary/mkt-original/mark.json (existing entries skipped by merge_comm)

Key decisions in this range:
- v1:1 huiou theou: textual variant — some MSS (Sinaiticus original) omit this phrase; UBS5 retains it
- v1:2: composite citation (Mal 3:1 + Isa 40:3) attributed solely to Isaiah — well-known textual crux
- v1:10 schizomenous: torn/split (not "opened") — more vivid than Matthew/Luke
- v1:12 ekballei: present tense "drives out" — Spirit\'s forceful agency, same verb as exorcisms
- v1:41 splagchnistheis vs. orgistheis: major textual variant — compassion vs. anger
- v2:20 aparthē: passion-prediction language, first in Mark
- v2:26 Abiathar: Mark names Abiathar where 1 Sam 21 places this under Ahimelech — classic crux
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    """Merge new_data into existing without overwriting present entries."""
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

MARK = {
  "1": {
    "2": '<p><strong>Kathos gegraptai en to Esaia to prophete</strong> — as it is written in Isaiah the prophet — the textual crux: what follows is a composite of Mal 3:1 (<em>idou apostellO ton angelon mou</em>, v.2b) and Isa 40:3 (v.3), yet the attribution names only Isaiah. Some manuscripts read "in the prophets" (<em>en tois prophetais</em>) to resolve the problem, but the earliest witnesses (Sinaiticus, Vaticanus) read "Isaiah the prophet." Mark headlines Isaiah as the dominant interpretive frame — Isa 40 opens the new-exodus prophecy of comfort, and the Malachi forerunner motif is absorbed under it. Both the messenger (Mal 3:1) and the voice (Isa 40:3) are read as the single figure John the Baptist.</p>',
    "3": '<p><strong>Phone boOntos en te eremo</strong> — the voice of one crying in the wilderness — Isa 40:3 LXX. The MT reads "in the wilderness prepare the way of the LORD," with the wilderness modifying the road to be prepared; the LXX (followed by all four Gospels) re-punctuates so that the voice is itself in the wilderness: "a voice crying in the wilderness." This makes the wilderness the location of the herald, not merely the destination of the road. <strong>Hetoimasate ten hodon kyriou</strong> — prepare the way of the Lord — in Isa 40 the <em>kyrios</em> is YHWH; the Gospels apply the title to Jesus, one of the most direct Lord = Jesus = YHWH equations in the NT, positioned at the Gospel\'s very opening.</p>',
    "4": '<p><strong>Baptisma metanoias eis aphesin hamartiOn</strong> — a baptism of repentance for/toward the forgiveness of sins — three theologically dense terms. <em>Baptisma</em> had precedents in Jewish proselyte immersion and Qumran practice but John\'s is distinctive: once-for-all, administered rather than self-immersion, linked to <em>metanoia</em>. <em>Metanoia</em> — repentance, change of mind and direction — is the whole-person turning. <em>Aphesis hamartiOn</em> — forgiveness/release of sins — the noun is the cognate of <em>aphiemi</em> (to release, forgive), used repeatedly in 2:5,7,9,10 for the paralytic\'s forgiveness: John\'s baptism promises release; Jesus accomplishes it by his own authority.</p>',
    "5": '<p><strong>Pasa he Ioudaia chOra kai hoi Ierosolymitai pantes</strong> — the whole Judean countryside and all the Jerusalemites — the double universalizing expression (<em>pasa</em> ... <em>pantes</em>) is Markan hyperbole for massive popular response, setting up the contrast with the religious authorities who will resist. <strong>Exomologoumenoi tas hamartias autOn</strong> — confessing their sins — the present participle indicates ongoing, iterative confession accompanying each individual baptism. Public verbal acknowledgment of sin is the marker of the genuine <em>metanoia</em> that John\'s baptism of repentance presupposes.</p>',
    "6": '<p><strong>Endedymenos trichas kamelou kai zOnen dermatinen peri ten osphyn autou</strong> — clothed in camel hair with a leather belt around his waist — the description echoes 2 Kgs 1:8 LXX, where the same phrase (<em>zOne dermatine</em>, leather belt) identifies Elijah the Tishbite to King Ahaziah. Mark\'s readers familiar with the LXX recognize the Elijah-figure before the explicit identification at 9:11-13. <strong>AkOrides kai meli agrion</strong> — locusts and wild honey — the wilderness diet: locusts are permitted insects (Lev 11:22) and honey from the wild; the diet of one outside the agricultural-economic system signals prophetic vocation and ascetic calling.</p>',
    "7": '<p><strong>Ho ischyroteros mou opisO mou erchetai</strong> — the one stronger than I is coming after me — <em>ischyroteros</em> (comparative of <em>ischyros</em>, strong/powerful) is the key Christological term: not merely "greater" in honor but stronger in power. The word anticipates the strong-man saying of 3:27 where Jesus binds the strong man to plunder his house — the coming one is stronger than the adversary John\'s language will later frame. <strong>Hou ouk eimi hikanos kypsas lysai ton himanta tOn hypodematOn autou</strong> — of whom I am not worthy, having stooped down, to untie the strap of his sandals — the most servile household task (sandal-removal by a slave) is what John considers beyond his appropriate role in relation to the coming one.</p>',
    "8": '<p><strong>Autos de baptisei hymas en pneumati hagiO</strong> — he will baptize you in the Holy Spirit — the contrast is precise: John\'s medium is water; the coming one\'s medium is Holy Spirit. Greek lacks the article before <em>pneumati hagiO</em> here, emphasizing the quality/character of the spirit rather than purely personal identity, though anarthrousness alone is not decisive. The preposition <em>en</em> (in/with) governs both: baptism in water (v.5) and baptism in Holy Spirit — same preposition, different media. The Spirit baptism draws on Isa 44:3; Ezek 36:25-27; Joel 2:28-29 — the eschatological outpouring of divine presence.</p>',
    "9": '<p><strong>Elthen Iesous apo Nazaret tes Galilaias</strong> — Jesus came from Nazareth of Galilee — the first appearance of Jesus in Mark\'s narrative: no birth, no genealogy, no infancy. Mark begins with the adult Jesus arriving for baptism. Nazareth was a small village (perhaps 400 residents) in the Galilean hills, socially unremarkable (cf. John 1:46). The geographic identification (<em>apo Nazaret tes Galilaias</em>) names his origin for those who will later question him (6:1-6). <strong>Ebaptisthe eis ton Iordanen hypo IOannou</strong> — was baptized in the Jordan by John — the passive emphasizes John\'s agency: Jesus submits to John\'s baptism rather than administering one.</p>',
    "10": '<p><strong>Schizomenous tous ouranous</strong> — the heavens being torn — the verb <em>schizO</em> (to split, tear, cleave) is more forceful than Matthew\'s and Luke\'s <em>anoigO</em> (to open). Isa 64:1 (MT) uses <em>qara\'</em> (tear) for the same longed-for divine advent: "Oh that you would tear the heavens and come down!" Mark\'s verb enacts the Isaianic prayer more vividly: the heavens are not gently parted but violently split. The same verb <em>schizO</em> appears at 15:38 for the temple curtain torn at the crucifixion — a deliberate structural inclusio: heavens torn at the Spirit\'s descent, curtain torn at Jesus\'s death.</p>',
    "11": '<p><strong>Sy ei ho huios mou ho agapetos</strong> — you are my beloved Son — the address is second person (<em>sy</em>), directly to Jesus, unlike Matthew\'s third-person announcement to bystanders. <em>Ho agapetos</em> (the beloved) carries the force of the Hebrew <em>yahid</em> (only, unique) — the love of the only son (cf. Gen 22:2 LXX where <em>agapetos</em> translates <em>yahid</em> for Isaac). The voice combines Ps 2:7 ("you are my Son") and Isa 42:1 ("my servant in whom my soul delights") — the royal psalm and the servant song. The dual citation at the baptism frames the entire Markan narrative: Son of God who is simultaneously Suffering Servant.</p>',
    "12": '<p><strong>Kai euthys to pneuma auton ekballei eis ten eremon</strong> — and immediately the Spirit drives him out into the wilderness — <em>euthys</em> (immediately) is the signature Markan adverb, appearing ~40 times. <em>Ekballei</em> (present tense indicative: drives out, expels) is the same verb used throughout Mark for casting out demons: the Spirit\'s action on Jesus employs the exorcism vocabulary rather than Matthew\'s gentler "led" (<em>anechthe</em>, 4:1). The Spirit who descended like a dove acts with the force of expulsion. The divine compulsion toward the messianic mission begins at once and without pause.</p>',
    "13": '<p><strong>Peirazomenos hypo tou Satana</strong> — being tempted by Satan — the present participle indicates ongoing temptation throughout the forty days, not a single sequence of three discrete tests as in Matthew and Luke. Mark gives no content to the temptations. <strong>En meta tOn theriOn</strong> — he was with the wild animals — unique to Mark, the detail has been read as Edenic restoration (Adam naming animals, Gen 2:19-20), as the new-creation peace of Isa 11:6-9; 65:25, or simply as wilderness desolation and danger. The angels attending him (<em>diekonoun autO</em>) provide the counterpoint: serviced by angels while threatened by the adversary and wild creation.</p>',
    "14": '<p><strong>Meta de to paradothenai ton IOannen</strong> — after John was delivered/handed over — the verb <em>paradothenai</em> (aorist passive of <em>paradidOmi</em>) is the passion verb throughout Mark: it will be used for Jesus\'s own betrayal and delivery to death (9:31; 10:33; 14:10,11,18,21,41,42,44; 15:1,10,15). Its first appearance is for John: the one who preceded Jesus in ministry and proclamation precedes him in being handed over. The passive voice implies divine purpose working through human agency. <strong>Euangelion tou theou</strong> — the gospel of God — the genitive <em>tou theou</em>: God as the source of the good news, not merely its subject.</p>',
    "16": '<p><strong>Paragon para ten thalassan tes Galilaias</strong> — passing alongside the Sea of Galilee — the participle <em>paragon</em> (passing by, traveling alongside) is casual: Jesus is in purposeful motion, not positioned at a call-station. The calling comes in the course of movement. <strong>Amphiballontas en te thalasse</strong> — casting (nets) into the sea — the present participle of <em>amphiballO</em> (to cast around on both sides, a circular casting-net technique) describes the brothers at their trade, unambiguously working when called. The call interrupts labor, not leisure.</p>',
    "17": '<p><strong>Deute opisO mou kai poieso hymas genesthai halieis anthrOpOn</strong> — come after me and I will make you become fishers of people — the construction <em>poieso hymas genesthai</em> (I will make you become) is emphatic: Jesus will be the agent of transformation. <em>Opiso mou</em> (behind/after me) is the discipleship-direction idiom: students walked behind their teacher. <em>Halieis anthrOpOn</em> — fishers of people — the vocational image extends: the skill-set changes while the activity-structure (casting, gathering) continues in a new domain. The Jer 16:16 echo (fishers gathering Israel for judgment) is reinterpreted toward gathering for the kingdom.</p>',
    "18": '<p><strong>Kai euthys aphentes ta diktya ekolouthEsan autO</strong> — and immediately, leaving their nets, they followed him — the three elements compress the call-response: <em>euthys</em> (immediately), <em>aphentes</em> (having abandoned — aorist participle of <em>aphiemi</em>, the leave/release/forgive verb), <em>ekolouthEsan</em> (followed — aorist). The nets are left mid-cast, not stowed; the abandonment is total and unreflective. Mark presents the call as carrying the imperatival force of a divine summons that admits no deliberation.</p>',
    "19": '<p><strong>Iakōbon ton tou Zebedaiou kai IOannEn ton adelphon autou</strong> — James the son of Zebedee and John his brother — James is consistently named first, consistent with his prominence in the early Jerusalem community (Acts 12:2). Both are identified by patronym (<em>tou Zebedaiou</em>) before by fraternal relationship, locating them in a family business. <strong>Katartizontas ta diktya</strong> — mending/preparing their nets — <em>katartizO</em> (to fit together, restore to proper condition, mend) describes routine net maintenance, the background work of a fishing operation. They are interrupted in preparatory work, not in active fishing.</p>',
    "20": '<p><strong>Kai euthys ekalesen autous</strong> — and immediately he called them — the same pattern as vv.17-18: immediate call, immediate response with no intervening discussion. <strong>Aphentes ton patera autOn Zebedaion en tO ploiO meta tOn misthiOn</strong> — leaving their father Zebedee in the boat with the hired men — the mention of hired men (<em>misthioi</em>) suggests a commercially viable enterprise rather than subsistence fishing. James and John leave not only their father but economic stability. Mark records neither Zebedee\'s reaction nor any farewell; the absoluteness of the departure is the point.</p>',
    "21": '<p><strong>Eisporeuontai eis Kapharnaoum</strong> — they entered Capernaum — the historic present (<em>eisporeuontai</em>) is characteristic Markan narrative vivid-tense; it gives the account an eyewitness immediacy. Capernaum (Tell Hum, northwest shore of the Sea of Galilee) becomes Jesus\'s Galilean base in Mark 1-6. <strong>Tois sabbasin eis ten synagOgen eiselthOn edidasken</strong> — on the Sabbath, having entered the synagogue, he was teaching — the imperfect <em>edidasken</em> indicates sustained activity. Jesus enters the existing institutional structure (the synagogue as communal assembly and Torah study center) on the Sabbath (maximum attendance day).</p>',
    "22": '<p><strong>Exeplessonto epi te didache autou</strong> — they were astonished/struck out at his teaching — <em>ekplesso</em> (to strike out, astonish — <em>ek</em>-prefix intensifies) is strong: the teaching struck them out of their existing framework. <strong>En gar didaskOn autous hos exousian echOn kai ouch hos hoi grammateis</strong> — for he was teaching them as one having authority, and not as the scribes — the contrast is between <em>exousia</em> (authority: inherent, primary, self-possessed) and the scribal method of citing received tradition ("Rabbi X says"). The scribes taught with derived authority; Jesus taught with primary authority. The crowd recognizes the formal difference before they can articulate its theological basis.</p>',
    "23": '<p><strong>En synagOge autOn anthrOpos en pneumati akathartO</strong> — in their synagogue a man in an unclean spirit — <em>en pneumati akathartO</em> (in an unclean spirit) is ambiguous: the man inhabits or is inhabited by the spirit — the preposition <em>en</em> denotes the sphere of influence. <em>Akathartos</em> (unclean) is the ritual-purity vocabulary of Leviticus 13-15 applied to a spirit: not merely a moral category but a cultic one, making the exorcism in the synagogue on the Sabbath simultaneously a power confrontation and a purity restoration.</p>',
    "24": '<p><strong>Ti hemin kai soi, IEsou NazarEne</strong> — what is there between us and you, Jesus of Nazareth — <em>ti hemin kai soi</em> is a rendering of the Hebrew idiom <em>mah-li wlak</em> (2 Sam 16:10; 1 Kgs 17:18): "what business do we have together?" or "do not interfere with us." The plural (<em>hemin</em> = us) reflects either a genuine plurality of possessing spirits or a collective of demonic forces. <strong>Ho hagios tou theou</strong> — the Holy One of God — the demon\'s title is the precise antonym of its own nature (<em>akathartos</em> = unclean): the Holy One confronts the unclean spirit in the sacred space of the synagogue, a triple contrast of holiness-uncleanness in the place of holiness.</p>',
    "25": '<p><strong>PhimOthEti kai exelthe ex autou</strong> — be muzzled and come out of him — <em>phimoo</em> (to muzzle, silence with a muzzle) is used of gagging working animals (Deut 25:4 LXX; 1 Cor 9:9) and of silencing human adversaries (Matt 22:34; 1 Pet 2:15). Jesus silences the demon before expelling it — the Messianic Secret begins with the forcible muzzling of demonic testimony, even accurate testimony about Jesus\'s identity. The two-part command addresses both speech (muzzle!) and presence (come out!), removing both the demonic voice and the demonic habitation.</p>',
    "26": '<p><strong>Kai sparaxan auton to pneuma to akatharton kai phOnEsan phOne megale exElthen ex autou</strong> — and having convulsed him, the unclean spirit, having cried out with a great voice, came out of him — the departure is violent (<em>sparaxan</em> = having convulsed, shaken violently) and audible (<em>phOnEsan phOne megale</em> = crying with a great voice). The violence demonstrates the exorcism\'s reality: the spirit is genuinely expelled against its resistance, not merely suppressed. The audible cry signals defeat. Mark preserves the phenomenological drama — Jesus\'s authority is exercised against genuine demonic opposition, not a ceremonial performance.</p>',
    "27": '<p><strong>Didache kaine kat\' exousian</strong> — new teaching according to authority — the crowd\'s synthesis of what they have witnessed: a <em>kaine didache</em> (new teaching; <em>kainos</em> = new in quality and kind, not merely recent) exercised <em>kat\' exousian</em> (in the mode of authority). The exorcism and the teaching are not separated — the same authority that distinguished the teaching of v.22 has now expelled a demon. <strong>Kai tois pneumasin tois akathartois epitassei, kai hypakouousin autO</strong> — he commands even the unclean spirits and they obey him — <em>epitassO</em> (to assign over, command authoritatively) + <em>hypakouO</em> (to hear under, to comply): military chain-of-command vocabulary applied to the spiritual realm.</p>',
    "28": '<p><strong>Exelthen hE akoe autou euthys pantachou eis holen ten periochon tes Galilaias</strong> — and immediately the report about him went out everywhere into the whole region of Galilee — <em>euthys</em> again; fame spreads with the same immediacy as the call responses and the exorcism. <em>AkoE</em> (hearing, report — from <em>akouO</em>) — the medium of fame is hearing-and-telling: what is heard is passed on. The geographic spread (<em>pantachou ... holen ten periochon</em> = everywhere ... the whole surrounding region) establishes that the Capernaum synagogue incident inaugurates the regional reputation that will drive the narrative\'s crowd dynamics in subsequent chapters.</p>',
    "29": '<p><strong>Kai euthys ek tes synagOgEs exelthontes Elthan eis ten oikian SimOnos kai Andreou</strong> — and immediately, going out of the synagogue, they entered the house of Simon and Andrew — <em>euthys</em> again; the domestic miracle immediately follows the public one. The house of Simon and Andrew in Capernaum is the domestic base for the early ministry; archaeological remains beneath the Byzantine church at Capernaum are identified by early pilgrims with Peter\'s house. The transition from synagogue to house moves from the institutional to the private, extending the authority of v.22-27 into the domestic sphere.</p>',
    "30": '<p><strong>He de penthera SimOnos katekeito pyressousa</strong> — the mother-in-law of Simon was lying down with a fever — <em>pethera</em> (mother-in-law) establishes that Simon is married before his call to discipleship, background to 1 Cor 9:5 where Paul mentions Peter traveling with a wife. <em>PyressO</em> (to be feverish) is a medical term; Luke 4:38 specifies "a great fever." <strong>Euthys legousin autO peri autes</strong> — immediately they spoke to him about her — the word <em>euthys</em> appears again; those with access to the healer immediately intercede for those who need him. The natural intercessory impulse is validated and answered at once.</p>',
    "31": '<p><strong>Kai proselthOn Egeiren auten kratEsas tes cheiros</strong> — and approaching, he raised her up, having grasped her hand — <em>egeirO</em> (to raise up) is the resurrection verb used for a healing: Jesus raises the feverish woman as he will raise the dead girl (5:41) and as he will be raised (16:6). The physical touch (<em>kratEsas tes cheiros</em>, grasping the hand) reverses the purity logic: contact with the sick normally transmits impurity; Jesus reverses the flow. <strong>AphEken auten ho pyretos</strong> — the fever left her — the fever is described as a subject that "leaves," like a spirit departing (same verb <em>aphiemi</em>). <strong>DiEkonei autois</strong> — she was serving them — immediate grateful service in the imperfect: the healed life restored to purposeful activity.</p>',
    "32": '<p><strong>Opsias de genomenes, hote edysen ho helios</strong> — when evening came, when the sun had set — the double temporal marker is precise: people waited until the Sabbath ended (sunset Saturday) to bring the sick, since carrying them constituted prohibited Sabbath labor. The careful notation reveals a Torah-observant community: the crowds waited for halakhic permission before acting on the healing-fame of v.28. <strong>Tous kakOs echontas kai tous daimonizomenous</strong> — those faring badly (sick) and those being demonized — Mark\'s two categories of affliction; both are addressed in the evening ministry that follows.</p>',
    "33": '<p><strong>Kai hE polis holE episynEgmene pros ten thyran</strong> — and the whole city had gathered at the door — the hyperbolic <em>hE polis holE</em> (the whole city, everyone) matches the <em>pasa hE Ioudaia chOra</em> of v.5. The gathering at the door (<em>epi ten thyran</em>) is spatially vivid: the private house becomes the site of what was hoped for in the temple — access to the divine presence that heals. The contrast with v.35 (Jesus rising before dawn to withdraw for prayer) sets up the tension between the crowd\'s demand and Jesus\'s self-directed mission-agenda.</p>',
    "34": '<p><strong>Kai ouk Ephien lalein ta daimonia, hoti Edeisan auton</strong> — and he did not permit the demons to speak, because they knew him — <em>Edeisan auton</em> (they knew him): the imperfect of <em>oida</em> (to know). The demons\' knowledge is ontological recognition, not acquired information; they perceive who Jesus is in a way that the human characters do not yet grasp. The silencing of demonic testimony (<em>ouk Ephien lalein</em>) is the second Messianic-Secret instance after v.25. Jesus suppresses accurate identification through unauthorized channels — the correct channel for Christological disclosure is the cross and resurrection, not demonic proclamation.</p>',
    "35": '<p><strong>Kai proi ennucha lian anastas exElthen kai apElthen eis eremon topon kakei prosEucheto</strong> — and very early while still night, having risen up, he went out and departed into a desolate place, and there he was praying — three temporal words pile up: <em>proi</em> (early), <em>ennucha</em> (while night), <em>lian</em> (exceedingly). The prayer precedes the day\'s work, in absolute predawn darkness. <em>Anastas</em> (having risen up) is the resurrection verb applied to rising from sleep; the pattern of predawn prayer recurs at 6:46 and 14:32-42. The <em>eremos topos</em> (desolate/desert place) echoes vv.3-4: the wilderness is the place of divine encounter, not merely absence and threat.</p>',
    "36": '<p><strong>Kai katedioxen auton SimOn kai hoi met\' autou</strong> — and Simon and those with him searched him out/pursued him — <em>katadiOkO</em> (to pursue, hunt down — the <em>kata</em> prefix intensifies) is a strong word for seeking: they hunted him rather than simply looked. The urgency implies the disciples\' agenda: return to the crowd, capitalize on the popularity. Simon is named first, establishing his leadership role among the first four disciples. The scene sets up the tension between the disciples\' crowd-driven logic and Jesus\'s mission-driven countermovement in v.38.</p>',
    "37": '<p><strong>Pantes zEtousin se</strong> — everyone is seeking you — the disciples\' report is an implicit call to return: demand is high, opportunity is ripe. But <em>zEtousin</em> (seeking, present indicative) in Mark rarely carries positive connotations: the same verb is used of those who seek to kill Jesus (11:18; 12:12; 14:1,11). The crowd seeks Jesus for healing; Jesus redirects away from meeting demand toward fulfilling mission. The disciples\' assumption — popularity equals success — will be corrected throughout Mark.</p>',
    "38": '<p><strong>Agomen allachou eis tas echomenas kOmopoleis hina kakei kEryxO</strong> — let us go elsewhere into the neighboring market-towns so that I may preach there also — <em>kOmopoleis</em> (town-villages, market-towns — NT hapax, combining <em>kOmE</em>, village, and <em>polis</em>, city) describes the semi-urban market centers of Galilee. <strong>Eis touto gar exElthon</strong> — for to this end I went out — <em>exElthon</em> (I went out) is grammatically ambiguous: proximately "went out from the house/Capernaum," but possibly carrying the theological sense of "came out from the Father" that John\'s Gospel articulates explicitly. The double resonance may be intentional in Mark\'s compact narration.</p>',
    "39": '<p><strong>Kai Elthen kErysson eis tas synagOgas autOn eis holen ten Galilaian kai ta daimonia ekballOn</strong> — and he went proclaiming in their synagogues into all Galilee and casting out demons — a summary statement of the early Galilean ministry, pairing the two activities: <em>kEryssO</em> (proclaim, herald) in synagogues and <em>ekballO daimonia</em> (cast out demons). The itinerant nature (<em>holen ten Galilaian</em> = all Galilee) and the synagogue-institution focus establish the Jewish-communal context of the mission. The regional exorcisms extend the Capernaum synagogue incident into a Galilee-wide pattern.</p>',
    "40": '<p><strong>Kai erchetai pros auton lepros parakalOn auton kai gonypetOn</strong> — and a leper came to him, imploring him, kneeling — <em>lepros</em> in the NT covers the range of skin conditions under the Hebrew <em>sara\'at</em> (Lev 13-14), not exclusively Hansen\'s disease. The legal consequence was communal exclusion: calling out "unclean!" and living apart (Lev 13:45-46). This man approaches Jesus in direct violation of the protocol. <em>GonypetOn</em> (kneeling) is formal supplication. <strong>Ean thelEs dynasai me katharisai</strong> — if you are willing, you are able to cleanse me — the question is not about Jesus\'s power (<em>dynasai</em> = you can, affirmed) but his will (<em>theleis</em>): the man is uncertain whether the healer will choose to act on his behalf.</p>',
    "41": '<p><strong>Kai splagchnistheis ektinas ten cheira Hepsato</strong> — and having been moved with compassion, stretching out his hand he touched — the major textual variant: Codex Bezae (D) and some Old Latin witnesses read <em>orgistheis</em> (having been angered) rather than <em>splagchnistheis</em> (having been moved with compassion). The harder-reading principle favors <em>orgistheis</em> — scribes were more likely to soften "anger" to "compassion" than vice versa — and some scholars argue Jesus\'s anger was at the disease, at the man\'s forced exclusion, or at the demonic affliction. The MKT follows the majority text with <em>splagchnistheis</em>. The verb <em>splagchnizomai</em> (from <em>splagchna</em>, viscera) describes visceral, gut-level compassion rather than surface sympathy.</p>',
    "42": '<p><strong>Euthys apElthen ap\' autou hE lepra kai ekatharisthE</strong> — immediately the leprosy left him and he was cleansed — <em>euthys</em>; the instantaneous healing is described in two parallel clauses: the disease left (<em>apElthen</em>, same verb for spirits departing) and the person was cleansed (<em>katharizO</em>, the ritual-purity verb used throughout this pericope at vv.40,41,42,44). Both the medical and the ritual dimension are restored simultaneously. The language of cleansing (<em>katharos/katharizO</em>) connects directly to Leviticus 13-14, whose cleansing-declaration process Jesus redirects back to its institutional channel in v.44.</p>',
    "43": '<p><strong>Kai embrimEsamenos autO euthys exebalen auton</strong> — and having strongly warned him he immediately sent him away — <em>embrimaomai</em> (from a root meaning to snort like a horse, hence: to groan strongly, charge sternly, be emotionally moved) appears in John 11:33,38 for Jesus\'s deep agitation at Lazarus\'s tomb. The word carries strong emotional charge beyond a merely verbal warning. <em>ExebalenTon</em> (he sent him away, drove him out — the exorcism verb) is striking: the same word used for casting out demons is used for sending this man away with urgency, reflecting the forcefulness of the command not to speak.</p>',
    "45": '<p><strong>Ho de exelthOn Erxato kEryssein polla kai diaphEmizein ton logon</strong> — but going out he began to proclaim many things and spread the word widely — the healed man disobeys the silence command (v.44): <em>diaphEmizO</em> (to spread abroad, broadcast) is the opposite of the commanded silence. <strong>HOste mEketi auton dynasthai phanerOs eis polin eiselthein</strong> — so that he could no longer openly enter a city — the disobedience has strategic consequences: Jesus\'s urban ministry is compromised by the resulting notoriety, forcing him to the desert places (<em>erEmois topois</em>). The irony closes the chapter: the healed outcast goes publicly where he was excluded; the healer who came publicly must now remain in the lonely places where the outcast formerly lived.</p>'
  },
  "2": {
    "1": '<p><strong>Kai eiselthOn palin eis Kapharnaoum di\' hemErOn</strong> — and having entered again into Capernaum after some days — <em>di\' hemErOn</em> (through days, after an interval of days) signals resumption of Capernaum-based ministry after the regional circuit of 1:39-45. <strong>Ekousthē hoti en oikO estin</strong> — it was heard that he was at home — <em>en oikO</em> (at home, in a house) may mean Simon\'s house (1:29-31) or a dwelling Jesus used regularly in Capernaum; the definite article\'s absence leaves both open. The spread of the report (<em>ekousthE</em> = it was heard, passive) without explicit announcement is consistent with the reputation-spreading dynamic of 1:28.</p>',
    "2": '<p><strong>Kai synagEchthEsan polloi hOste mEketi chOrein mEde ta pros ten thyran</strong> — and many gathered so that there was no longer room even at the door — the spatial overflow repeats the pattern of 1:33 (the whole city at the door). <strong>Kai elalei autois ton logon</strong> — and he was speaking the word to them — <em>ton logon</em> (the word) without specification: early Christian usage of <em>logos</em> as a technical term for the gospel message is operative. Mark\'s narrative compresses the crowd scene into one clause and moves immediately to the rooftop drama — the preaching is background to the healing.</p>',
    "3": '<p><strong>Kai erchontai pherein pros auton paralytikon airomenon hypo tessarOn</strong> — and they came bringing to him a paralyzed man carried by four — <em>paralytikos</em> (from <em>paraluO</em> = to loosen beside, to unloose the motor faculty) is the clinical term for motor incapacity. The specification of four carriers (<em>hypo tessarOn</em>) is precise and picturesque: the roof operation requires four people at the corners of the mat. The verb <em>pherO</em> (to carry, bear — also to bring an offering) creates the image of an offering of need being presented to the healer.</p>',
    "4": '<p><strong>Kai mE dynamis prosengisai autO dia ton ochlon apestegasan ten stegen hopou En</strong> — and not being able to bring him near because of the crowd, they unroofed the roof where he was — <em>apestegasan ten stegen</em> (they unroofed the roof) is the NT hapax verb <em>apostegazO</em>. A Palestinian peasant roof was typically packed earth on wooden beams or interlaid branches, accessible by an outside staircase. Opening it required deliberate demolition: removing material to create a hole large enough for the mat. <strong>Exoruxantes chalaOsin ton krabbaton</strong> — having dug through they lowered the mat — <em>krabbatos</em> (pallet, cot — low-register word for a simple sleeping mat) marks the social status of the man being lowered.</p>',
    "5": '<p><strong>IdOn de ho Iesous ten pistin autOn</strong> — seeing their faith — the object of <em>idOn</em> (having seen) is <em>ten pistin autOn</em> (their faith): what Jesus sees is the visible, enacted faith of those who demolished a roof. Faith in Mark is demonstrated through action rather than verbal confession; the observable expression of faith (the physical effort) is what Jesus perceives. <strong>Teknon, aphiontai sou hai hamartiai</strong> — child, your sins are being forgiven — <em>teknon</em> (child, term of affection) is the intimate pastoral address. <em>Aphiontai</em> (present passive: are being forgiven, are being released) — the forgiveness is active in the present moment of speech, not a future promise.</p>',
    "6": '<p><strong>Esan de tines tOn grammateOn ekei kathEmenoi kai dialogizomenoi en tais kardiais autOn</strong> — but there were some of the scribes sitting there and deliberating in their hearts — <em>dialogizomai</em> (to reason through, deliberate — <em>dia</em> + <em>logos</em>) carries the sense of working through a problem argument by argument. The scribes reason silently — <em>en tais kardiais autOn</em> (in their hearts), the seat of thought in Hebrew-Jewish anthropology. Their internal deliberation is private until Jesus reads it (v.8).</p>',
    "7": '<p><strong>Ti houtos houtOs lalei? Blasphemei</strong> — why does this one speak thus? He blasphemes — <em>blaspheO</em> (to harm/injure the divine reputation) was punishable by death under Lev 24:16. The scribes\' theological reasoning is internally coherent: <em>tis dynatai aphienai hamartias ei me heis ho theos</em> — who can forgive sins except one, God? The premise is correct (forgiveness is God\'s prerogative); the conclusion (therefore Jesus is blaspheming) fails only if Jesus is who Mark has already announced him to be (Son of God, 1:1). The passage\'s Christological argument turns precisely on that identification.</p>',
    "8": '<p><strong>Kai euthys epignous ho Iesous tO pneumati autou hoti houtOs dialogizontai en heautois</strong> — and immediately, knowing by his spirit that thus they were deliberating within themselves — <em>epiginOskO</em> (to know fully/completely) in the aorist participle: immediate and complete perception. <em>TO pneumati autou</em> (by/in his spirit) — direct spiritual knowledge, not deductive inference. In OT theology, knowledge of the heart\'s contents belongs to God alone (Jer 17:9-10; Ps 139:1-4; 1 Sam 16:7). Jesus\'s perception of unspoken thoughts enacts a divine prerogative, making the verse a Christological argument embedded in the healing narrative.</p>',
    "9": '<p><strong>Ti estin eukopOteron, eipein tO paralytikO, Aphiontai sou hai hamartiai, E eipein, Egeire kai aron ton krabbaton sou kai peripatei</strong> — which is easier, to say to the paralyzed man "your sins are being forgiven," or to say "rise and take your mat and walk"? — the rhetorical comparison (<em>eukopOteron</em> = easier) is a standard argument from the greater to the lesser. Pronouncing forgiveness is verbally unverifiable by human observers; commanding a paralyzed man to rise is immediately and publicly verifiable. If the verifiable thing is accomplished, the unverifiable claim is thereby vindicated. The question does not deny the charges but reframes them on verifiable grounds.</p>',
    "11": '<p><strong>Soi legO, egeire aron ton krabbaton sou kai hypage eis ton oikon sou</strong> — I say to you, rise, take your mat and go to your house — the three imperatives address the paralyzed man directly: <em>egeire</em> (rise — the resurrection verb as a command before the restoration), <em>aron</em> (take up), <em>hypage</em> (go). The command asserts motor function before it has been demonstrated. The reversal encoded in <em>aron ton krabbaton</em> (carry the mat) is pointed: the man carried on his mat will carry the mat. He who was dependent will now bear his own means of dependence as a trophy of the healing.</p>',
    "12": '<p><strong>Kai Egerthē kai euthys aras ton krabbaton exElthen emprosthen pantOn</strong> — and he was raised up and immediately, having taken up the mat, he went out before all — <em>egerthE</em> (was raised up, passive — the resurrection passive, the same form used at 16:6 for the resurrection of Jesus). The three actions mirror the three commands of v.11: he rose, he took the mat, he went. <strong>Oidamen hoti houtOs oudepote eidamen</strong> — we have never seen it thus — the historical "never before" marks the unprecedented character of what has occurred. The crowd\'s amazement (<em>existasthai</em> = to stand outside oneself, to be beside oneself with astonishment) is the collective witness to the Christological claim enacted in the healing.</p>',
    "13": '<p><strong>Kai exElthen palin para ten thalassan</strong> — and he went out again alongside the sea — the spatial rhythm of Mark\'s narrative: crowded house → open lakeshore. <strong>Pas ho ochlos Ercheto pros auton, kai edidasken autous</strong> — all the crowd came to him and he was teaching them — the imperfect <em>edidasken</em> indicates sustained teaching. The lakeside setting (open, informal, accessible from any direction) contrasts with the synagogue (structured, institutional, weekly). Jesus uses both venues: the teaching authority of v.22 operates in both settings.</p>',
    "14": '<p><strong>Leuin ton tou Alphaiou kathEmenon epi to telOnion</strong> — Levi the son of Alphaeus sitting at the tax booth — the tax/toll collector (<em>telOnEs</em>) at his station (<em>telOnion</em>, tax-booth, customs post) was typically positioned at a road, bridge, or city gate to levy tolls on goods. The identification "of Alphaeus" (<em>tou Alphaiou</em>) appears also at 3:18 for James son of Alphaeus, raising the question of fraternal relationship and identification with Matthew (Matt 9:9; 10:3). The call pattern is the same as 1:17-20: Jesus passing, seeing, two-word call, immediate compliance.</p>',
    "15": '<p><strong>Polloi telOnai kai hamartOloi synanekeinto tO IEsou kai tois mathEtais autou</strong> — many tax collectors and sinners were reclining at table with Jesus and his disciples — <em>synanakeimai</em> (to recline with at table) is the technical vocabulary for table fellowship in the Greco-Roman meal posture. Eating with someone in antiquity declared social solidarity and, for Jews, implied ritual compatibility. <em>HamartOloi</em> (sinners) here likely designates those who did not observe Torah in the Pharisaic manner — particularly regarding tithing, purity, and sabbath — rather than generically immoral persons.</p>',
    "16": '<p><strong>Hoi grammateis tOn PharisaiOi idontes hoti esthiei meta tOn hamartOlOn kai telOnOn elegon tois mathEtais autou</strong> — the scribes of the Pharisees seeing that he eats with sinners and tax collectors said to his disciples — "scribes of the Pharisees" is more specific than "scribes": Torah-scholars operating within the Pharisaic purity program. The challenge is directed at the disciples (<em>tois mathEtais autou</em>) rather than at Jesus — a rhetorical strategy to undermine the teacher through his students. The question is indirect: "why does he eat with tax collectors and sinners?" addressed to those who should be enforcing proper standards on their teacher.</p>',
    "17": '<p><strong>Ou chreian echousin hoi ischyontes iatrou all\' hoi kakOs echontes</strong> — those who are strong do not need a physician but those who are sick — the medical analogy is self-evident and irrefutable: physicians go where illness is. The force of the analogy reframes the table-fellowship charge: if he associates with sinners, it is because sinners are his practice, not because he endorses their condition. <strong>Ouk Elthon kalesai dikaious alla hamartOlous</strong> — I did not come to call the righteous but sinners — <em>kalesai</em> (to call) picks up the discipleship-call language of the chapter: the tax collector was "called" (v.14), and the mission is to call those who are sinners. The possible irony: those who consider themselves <em>dikaious</em> (righteous) have no perceived need of the physician and thus place themselves outside his reach.</p>',
    "18": '<p><strong>Kai Esan hoi mathEtai IOannou kai hoi PharisaiOi nEsteuontes</strong> — and the disciples of John and the Pharisees were fasting — the combination of John\'s disciples and the Pharisees as co-fasting groups is notable: they are theologically distinct communities aligned on this specific practice. The fasting at issue is voluntary piety-fasting (Pharisaic practice: Monday and Thursday), not the Yom Kippur fast required by Torah. The question comes from unnamed questioners (<em>erchontai kai legousin</em> = they come and say), creating an open challenge rather than a named-group confrontation.</p>',
    "20": '<p><strong>Eleusontai de hEmerai hotan aparthE ap\' autOn ho nymphios, kai tote nEsteusousin en ekeinE tE hEmera</strong> — but days will come when the bridegroom will be taken away from them, and then they will fast on that day — <em>aparthE</em> (aorist passive subjunctive of <em>apairO</em>, to take away, lift off by force) is the first unambiguous passion prediction in Mark: the bridegroom will be <em>taken away</em>. The passive voice indicates violent removal rather than voluntary departure. <em>Tote nEsteusousin</em> (then they will fast) — fasting is reinterpreted as the practice of mourning and eschatological waiting appropriate to the period of the bridegroom\'s absence after his death, not appropriate to the presence-period of his earthly ministry.</p>',
    "21": '<p><strong>Epiblēma rhakous agnaphou epirraptei epi himation palaion</strong> — no one sews a patch of unshrunk cloth on an old garment — <em>agnaphos</em> (unfulled, unshrunk — <em>a-</em> privative + <em>gnaptO</em>, to card or full cloth) is cloth that has not undergone the shrinking process; sewn to a worn garment it will pull away when washed, making the tear worse. <em>Palaion</em> (old, worn out — from <em>palaioo</em>, to make obsolete) is the key term for the old order. The metaphor establishes that the new content of the kingdom is qualitatively incompatible with the old wineskin/garment structures — not that the old was bad, but that the new cannot be contained within it.</p>',
    "22": '<p><strong>Kai oudeis ballei oinon neon eis askous palaiOus</strong> — no one pours new wine into old wineskins — the second metaphor. The wine is <em>neon</em> (recently made, young, still fermenting) and the skins must be new to expand with it; old skins have lost their elasticity. Note the vocabulary distinction: v.21 uses <em>agnaphos/kainos</em> (new in kind); v.22 uses <em>neos</em> (new in time). <em>Kainos</em> (qualitatively new) and <em>neos</em> (recently made) are distinct: the kingdom is both qualitatively new (unprecedented in kind) and freshly inaugurated (recently arrived). Both dimensions require new structures — not patchwork accommodations within the existing system.</p>',
    "23": '<p><strong>Kai egeneto auton en tois sabbasin paraporeuesthai dia tOn sporImOn</strong> — and it happened that on the Sabbath he was passing through the grain fields — <em>paraporeuesthai</em> (to travel alongside, pass through) is movement through fields, not active harvesting. The disciples\' action (<em>Erxanto hodon poiein tillontes tous stachyas</em> = began to make a way plucking heads of grain) was permitted for hungry travelers by Deut 23:25, but the Pharisees classify it as reaping under the Sabbath restrictions. The controversy is not about Torah violation per se but about Pharisaic <em>halakhah</em> that expanded the Sabbath reaping-prohibition to cover gleaning. Jesus\'s counterargument operates on the level of hermeneutical principle, not merely exception.</p>',
    "24": '<p><strong>Ide, ti poiousin tois sabbasin ho ouk exestin?</strong> — see, why do they do on the Sabbath what is not lawful? — <em>exestin</em> (it is lawful/permitted) is the halakhic permissibility verb. The Pharisees address Jesus rather than the disciples — the teacher is responsible for students\' behavior. The challenge is not to the disciples\' hunger but to Jesus\'s halakhic teaching: he is being charged with licensing unlawful behavior. Jesus responds not by arguing the exception but by challenging the premises: David overrode a more serious prohibition; the Sabbath was made for humanity; the Son of Man is its Lord.</p>',
    "25": '<p><strong>Oudepote anegnOte ho epoiEsen Dauid, hote chreian eschen</strong> — have you never read what David did when he was in need — the appeal to scripture (<em>ouk anegnOte</em> = have you not read?) is Jesus\'s standard debate-opening (also 10:9; 12:10,26). The David precedent (1 Sam 21:1-6) establishes that <em>chreian eschen</em> (pressing need) overrode the purity restriction on the bread of the Presence. The argument is from precedent: if the anointed king\'s need overrode a specific ritual prohibition, the disciples\' hunger can override a secondary Sabbath restriction derived from Torah by Pharisaic extension.</p>',
    "26": '<p><strong>Epi Abiathar archiereos</strong> — in the days of Abiathar the high priest — the historical crux: 1 Sam 21:1-6 places the incident under <em>Ahimelech</em>, not Abiathar. Abiathar was Ahimelech\'s son, who became the prominent high priest of David\'s reign (2 Sam 15:35; 1 Kgs 2:26-27). Proposed explanations: (1) an early traditional slip, preserved by Mark; (2) the phrase means "in the section about Abiathar the high priest" (the more famous of the two, used to identify the scriptural passage); (3) the two priests may have shared the office temporarily. No fully satisfying resolution exists; the phrase is the most-discussed historical difficulty in Mark. <em>Tous artous tEs prothEseOs</em> (the bread of Presentation/Setting-Out) is the showbread of Lev 24:5-9, restricted to Aaronic priests.</p>',
    "27": '<p><strong>To sabbaton dia ton anthropon egeneto kai ouch ho anthrOpos dia to sabbaton</strong> — the Sabbath came into being for the sake of humanity and not humanity for the sake of the Sabbath — this verse is unique to Mark; neither Matthew nor Luke includes it, moving directly to v.28. <em>Dia ton anthropon</em> (for the sake of humanity/the human being) is the teleological statement: the Sabbath was created as a gift and provision (Gen 2:1-3; Exod 20:8-11; Deut 5:12-15), not a burdensome institution. The principle reverses the Pharisaic trajectory: they had made human beings serve the Sabbath-institution; Jesus restores the Sabbath to its intended direction of service toward humanity.</p>',
    "28": '<p><strong>HOste kyrios estin ho huios tou anthrOpou kai tou sabbatou</strong> — so the Son of Man is Lord even of the Sabbath — the argument\'s climax: <em>kyrios</em> (lord, master, owner) of the Sabbath belongs to the Son of Man. The <em>kai</em> (even) is emphatic: of the Sabbath itself, the institution that God established in creation. The Son of Man language carries the Dan 7:13-14 resonances of the one given universal authority and dominion. The claim moves from humanitarian argument (v.27: Sabbath for humanity) to Christological claim (v.28: the Son of Man is its Lord), making the final word of the chapter a direct assertion of Messianic authority over the Sabbath\'s meaning.</p>'
  }
}

def main():
    existing = load_comm('mkt-original', 'mark')
    merge_comm(existing, MARK)
    save_comm('mkt-original', 'mark', existing)
    print('Mark 1-2 mkt-original written.')

if __name__ == '__main__':
    main()
